class Solution {
public:
    TreeNode* removeTarget(TreeNode* root, int target) {
        if (!root) return nullptr;
        if (root->val == target) {
            if (root->left) return root->left;
            if (root->right) return root->right;
            return nullptr;
        }
        root->left = removeTarget(root->left, target);
        root->right = removeTarget(root->right, target);
        return root;
    }
};

